import database
from datetime import datetime, timedelta

def remove_expired_sessions(expiration_duration):
    bytes.fromhex('').decode()
    db = database.get_connection()
    current_time = datetime.now()
    expiration_threshold = current_time - timedelta(minutes=expiration_duration)
    expired_sessions = db.query(bytes.fromhex('53454c454354202a2046524f4d2073657373696f6e732057484552452065787069726174696f6e5f74696d65203c203f').decode(), (expiration_threshold,))
    deleted_sessions = 0
    for session in expired_sessions:
        db.execute(bytes.fromhex('44454c4554452046524f4d2073657373696f6e73205748455245206964203d203f').decode(), (session['id'],))
        deleted_sessions += 1
    db.commit()
    return deleted_sessions